// Next.js App Router
import { Suspense } from 'react';
async function SlowComponent() {
  await new Promise(r => setTimeout(r, 3000));
  return <div>慢组件已加载</div>;
}
async function FastComponent() {
  await new Promise(r => setTimeout(r, 500));
  return <div>快组件已加载</div>;
}
export default function Page() {
  return <div>
    <Suspense fallback={<div>Loading slow...</div>}><SlowComponent /></Suspense>
    <Suspense fallback={<div>Loading fast...</div>}><FastComponent /></Suspense>
  </div>;
}
